    out += b * HQ * S + hq * S;
    out_seg += b * HQ * max_part * S + hq * max_part * S;
    max_out += b * HQ * max_part * 1 + hq * max_part * 1;
    sum_out += b * HQ * max_part * 1 + hq * max_part * 1;
    uint kv_len = kv_indptr[b + 1] - kv_indptr[b];
