   620	        auto cur_max = max_out[i];
   621	        auto cur_out_seg = out_seg + i * S;
   622	        const float part_scale = sum_out[i] * __expf(cur_max - real_max);
   623	        for (uint head_part = 0; head_part < HEAD_128_PARTS; head_part++) {
   624	            auto cur_val_low = ((bfloat16x2*)cur_out_seg)[lane_id + head_part * 64];
   625	            float32x2 tmp_val;
   626	            tmp_val[0] = cur_val_low[0];
   627	            tmp_val[1] = cur_val_low[1];
   628	            cur_val[head_part] += tmp_val * part_scale;
   629	        }
   630	        warp_sum += part_scale;
   631	    }
   632	
   633	    __shared__ float out_lds[4 * S];
   634	    __shared__ float sum_lds[4];
   635	    if (lane_id == 0) {
   636	        sum_lds[warp_id] = warp_sum;
   637	    }
   638	    if (warp_id != 0) {
   639	        for (uint head_part = 0; head_part < HEAD_128_PARTS; head_part++) {
   640	            *(float32x2*)(&out_lds[warp_id * S + head_part * 128 + lane_id * 2]) = cur_val[head_part];
   641	        }
   642	    }
   643	    __syncthreads();
   644	    if (warp_id == 0) {
   645	        warp_sum += sum_lds[1] + sum_lds[2] + sum_lds[3];
   646	        for (int i = 1; i < 4; i++) {
   647	            for (uint head_part = 0; head_part < HEAD_128_PARTS; head_part++) {
   648	                cur_val[head_part] += *(float32x2*)(&out_lds[i * S + head_part * 128 + lane_id * 2]);
   649	            }
   650	        }
   651	        const float inv_sum_scale = 1.f / (warp_sum + 1e-6f);
   652	        for (uint head_part = 0; head_part < HEAD_128_PARTS; head_part++) {
   653	            cur_val[head_part] *= inv_sum_scale;
   654	            bfloat16x2 tmp_val;
   655	            tmp_val[0] = cur_val[head_part][0];
   656	            tmp_val[1] = cur_val[head_part][1];
   657	            ((bfloat16x2*)out)[lane_id + head_part * 64] = tmp_val;
   658	        }
   659	    }
   660	}
